-- ═══════════════════════════════════════════════════════════════
-- Seed: massive gig pack (~70 extra demo gigs across all countries)
-- ═══════════════════════════════════════════════════════════════
-- Populates the Gig Market so every country and category has
-- plenty of gigs to browse. Each gig is attached to a random
-- demo designer from the matching country. Idempotent — skips
-- titles that already exist.

-- Ensure the FK is gone (safe if already dropped)
ALTER TABLE public.designer_gigs
    DROP CONSTRAINT IF EXISTS designer_gigs_designer_id_fkey;

-- Pick one demo designer per (country, row_number) so we can
-- distribute gigs across multiple designers per country.
WITH picks AS (
    SELECT country, id AS designer_id,
           ROW_NUMBER() OVER (PARTITION BY country ORDER BY display_name) AS rn
    FROM public.designer_profiles WHERE is_demo = true
)
INSERT INTO public.designer_gigs
    (designer_id, title, category, description, tags, country,
     thumbnail, gallery, standard_price, standard_days, standard_revisions, standard_desc,
     has_deluxe, deluxe_price, deluxe_days, deluxe_revisions, deluxe_desc,
     has_premium, premium_price, premium_days, premium_revisions, premium_desc,
     status, view_count, order_count, avg_rating, total_reviews)
SELECT p.designer_id, s.title, s.category, s.description, s.tags::jsonb, s.country,
       s.thumb, s.gallery::jsonb,
       s.std_price, s.std_days, s.std_rev, s.std_desc,
       s.has_dlx, s.dlx_price, s.dlx_days, s.dlx_rev, s.dlx_desc,
       s.has_prm, s.prm_price, s.prm_days, s.prm_rev, s.prm_desc,
       'active', s.views, s.orders, s.rating, s.reviews
